import { useRef, useState } from "react";
import ChartCard from "./ChartCard";
import InsightPanel from "./InsightPanel";
import VoicePanel from "./VoicePanel";

// Load html2canvas from CDN
function loadH2C() {
  return new Promise((res, rej) => {
    if (window.html2canvas) { res(window.html2canvas); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js";
    s.onload = () => res(window.html2canvas);
    s.onerror = rej;
    document.head.appendChild(s);
  });
}

// Capture the charts grid as a canvas
async function captureElement(el) {
  const h2c = await loadH2C();
  return h2c(el, {
    backgroundColor: "#0b0f1a",
    scale: 2,
    useCORS: true,
    allowTaint: true,
    logging: false,
    scrollX: 0,
    scrollY: 0,
    windowWidth: el.scrollWidth,
    windowHeight: el.scrollHeight,
  });
}

export default function DashboardScreen({ data, sessionId, colorSchema, onReset }) {
  const { dashboard_title, charts, insights, summary, total_kpis_generated } = data;
  const exportRef = useRef(null);
  const [exporting, setExporting] = useState(false);
  const [exportType, setExportType] = useState("");
  const [showMenu, setShowMenu] = useState(false);

  const voiceContext = charts.map((c) => ({
    kpi: c.kpi, chart_type: c.chart_type, data: c.data.slice(0, 20),
  }));

  // ── PNG Export ────────────────────────────────────────────────────────────
  const exportPNG = async () => {
    setShowMenu(false); setExporting(true); setExportType("png");
    try {
      const canvas = await captureElement(exportRef.current);
      const link = document.createElement("a");
      link.download = `${dashboard_title.replace(/\s+/g, "_")}.png`;
      link.href = canvas.toDataURL("image/png", 1.0);
      link.click();
    } catch (e) {
      alert("PNG export failed: " + e.message);
    } finally { setExporting(false); setExportType(""); }
  };

  // ── PDF Export — professional layout ─────────────────────────────────────
  const exportPDF = async () => {
    setShowMenu(false); setExporting(true); setExportType("pdf");
    try {
      const canvas  = await captureElement(exportRef.current);
      const imgData = canvas.toDataURL("image/png", 0.95);
      const date    = new Date().toLocaleDateString("en-US", { year:"numeric", month:"long", day:"numeric" });

      // Build insight rows for the PDF summary table
      const insightRows = insights.slice(0, 3).map((ins) => `
        <div class="insight-card">
          <div class="insight-kpi">${ins.kpi}</div>
          <div class="insight-row"><span class="ilabel">📊 Descriptive</span><span class="itext">${ins.descriptive || ""}</span></div>
          <div class="insight-row"><span class="ilabel">💡 Prescriptive</span><span class="itext">${ins.prescriptive || ""}</span></div>
        </div>
      `).join("");

      const pw = window.open("", "_blank");
      if (!pw) { alert("Allow popups for this site to export PDF."); setExporting(false); return; }

      pw.document.write(`<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8"/>
  <title>${dashboard_title}</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

    * { margin:0; padding:0; box-sizing:border-box; }

    body {
      font-family: 'Inter', sans-serif;
      background: #ffffff;
      color: #1e293b;
      font-size: 13px;
      line-height: 1.6;
    }

    /* ── Cover page ─────────────────────── */
    .cover {
      min-height: 100vh;
      background: linear-gradient(135deg, #0b0f1a 0%, #1a2236 50%, #0b0f1a 100%);
      display: flex;
      flex-direction: column;
      justify-content: space-between;
      padding: 60px 70px;
      page-break-after: always;
    }

    .cover-header {
      display: flex;
      align-items: center;
      gap: 16px;
    }

    .cover-logo {
      width: 48px; height: 48px;
      background: rgba(99,102,241,0.15);
      border: 1px solid rgba(99,102,241,0.3);
      border-radius: 14px;
      display: flex; align-items: center; justify-content: center;
      font-size: 22px;
    }

    .cover-brand {
      font-size: 18px; font-weight: 700;
      color: #e2e8f8; letter-spacing: -0.3px;
    }

    .cover-brand span { color: #6366f1; }

    .cover-center {
      flex: 1;
      display: flex;
      flex-direction: column;
      justify-content: center;
      padding: 80px 0 40px;
    }

    .cover-eyebrow {
      font-size: 11px; font-weight: 600;
      color: #6366f1; letter-spacing: 0.15em;
      text-transform: uppercase; margin-bottom: 20px;
    }

    .cover-title {
      font-size: 52px; font-weight: 700;
      color: #ffffff; line-height: 1.15;
      letter-spacing: -1px; margin-bottom: 20px;
    }

    .cover-subtitle {
      font-size: 18px; color: #8896b3;
      font-weight: 300; margin-bottom: 48px;
    }

    .cover-divider {
      width: 64px; height: 3px;
      background: linear-gradient(90deg, #6366f1, #a855f7);
      border-radius: 2px; margin-bottom: 48px;
    }

    .cover-stats {
      display: flex; gap: 40px;
    }

    .cover-stat-num {
      font-size: 36px; font-weight: 700;
      color: #6366f1; letter-spacing: -1px;
      display: block;
    }

    .cover-stat-lbl {
      font-size: 12px; color: #8896b3;
      text-transform: uppercase; letter-spacing: 0.08em;
    }

    .cover-footer {
      display: flex; justify-content: space-between; align-items: center;
      padding-top: 32px;
      border-top: 1px solid rgba(255,255,255,0.08);
    }

    .cover-footer p { font-size: 12px; color: #3d4f70; }
    .cover-footer .date { color: #8896b3; }

    /* ── Dashboard page ─────────────────── */
    .dash-page {
      background: #0b0f1a;
      padding: 0;
      page-break-after: always;
    }

    .dash-header {
      background: #111827;
      padding: 20px 32px;
      border-bottom: 1px solid #243048;
      display: flex; justify-content: space-between; align-items: center;
    }

    .dash-header h2 {
      font-size: 16px; font-weight: 700; color: #e2e8f8;
    }

    .dash-header p { font-size: 11px; color: #8896b3; margin-top: 2px; }

    .dash-badge {
      padding: 4px 12px;
      background: rgba(99,102,241,0.1);
      border: 1px solid rgba(99,102,241,0.2);
      border-radius: 20px;
      color: #6366f1; font-size: 11px; font-weight: 600;
    }

    .dash-img { width: 100%; display: block; }

    /* ── Insights page ──────────────────── */
    .insights-page {
      background: #ffffff;
      padding: 60px 70px;
      page-break-before: always;
    }

    .page-header {
      display: flex; justify-content: space-between; align-items: flex-start;
      margin-bottom: 40px; padding-bottom: 24px;
      border-bottom: 2px solid #f1f5f9;
    }

    .page-title { font-size: 28px; font-weight: 700; color: #1e293b; margin-bottom: 6px; }
    .page-sub   { font-size: 13px; color: #64748b; }
    .page-num   { font-size: 11px; color: #94a3b8; text-align: right; }

    .summary-box {
      background: linear-gradient(135deg, #6366f1 0%, #a855f7 100%);
      border-radius: 14px;
      padding: 28px 32px;
      margin-bottom: 36px;
      color: white;
    }

    .summary-box h3 {
      font-size: 11px; font-weight: 600; letter-spacing: 0.12em;
      text-transform: uppercase; opacity: 0.7; margin-bottom: 12px;
    }

    .summary-box p { font-size: 15px; line-height: 1.8; opacity: 0.95; }

    .section-title {
      font-size: 14px; font-weight: 700; color: #1e293b;
      text-transform: uppercase; letter-spacing: 0.06em;
      margin-bottom: 20px; padding-bottom: 10px;
      border-bottom: 2px solid #f1f5f9;
    }

    .insight-card {
      background: #f8fafc;
      border: 1px solid #e2e8f0;
      border-radius: 12px;
      padding: 20px 24px;
      margin-bottom: 16px;
    }

    .insight-kpi {
      font-size: 14px; font-weight: 700; color: #6366f1;
      margin-bottom: 14px; padding-bottom: 10px;
      border-bottom: 1px solid #e2e8f0;
    }

    .insight-row {
      display: flex; gap: 12px;
      margin-bottom: 10px; align-items: flex-start;
    }

    .ilabel {
      font-size: 11px; font-weight: 600; color: #64748b;
      width: 120px; flex-shrink: 0;
      text-transform: uppercase; letter-spacing: 0.05em;
      padding-top: 2px;
    }

    .itext { font-size: 13px; color: #334155; line-height: 1.65; flex: 1; }

    /* ── Footer on each page ────────────── */
    .pdf-footer {
      position: fixed; bottom: 0; left: 0; right: 0;
      height: 36px;
      background: #f8fafc;
      border-top: 1px solid #e2e8f0;
      display: flex; justify-content: space-between; align-items: center;
      padding: 0 70px;
      font-size: 10px; color: #94a3b8;
    }

    @media print {
      body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
      @page { margin: 0; size: A4 portrait; }
      .pdf-footer { position: fixed; }
    }
  </style>
</head>
<body>

  <!-- ── Page 1: Cover ───────────────────────────────────────────── -->
  <div class="cover">
    <div class="cover-header">
      <div class="cover-logo">📊</div>
      <div class="cover-brand">Talking <span>BI</span></div>
    </div>

    <div class="cover-center">
      <div class="cover-eyebrow">Business Intelligence Report</div>
      <div class="cover-title">${dashboard_title}</div>
      <div class="cover-subtitle">AI-Generated Dashboard & Analytics Report</div>
      <div class="cover-divider"></div>
      <div class="cover-stats">
        <div>
          <span class="cover-stat-num">${total_kpis_generated}</span>
          <span class="cover-stat-lbl">Charts Generated</span>
        </div>
        <div>
          <span class="cover-stat-num">${insights.length}</span>
          <span class="cover-stat-lbl">KPIs Analyzed</span>
        </div>
        <div>
          <span class="cover-stat-num">6</span>
          <span class="cover-stat-lbl">Insight Types</span>
        </div>
      </div>
    </div>

    <div class="cover-footer">
      <p>Confidential · Generated by Talking BI</p>
      <p class="date">${date}</p>
    </div>
  </div>

  <!-- ── Page 2: Dashboard Charts ───────────────────────────────── -->
  <div class="dash-page">
    <div class="dash-header">
      <div>
        <h2>${dashboard_title}</h2>
        <p>Dashboard Overview · ${date}</p>
      </div>
      <div class="dash-badge">${total_kpis_generated} Visualizations</div>
    </div>
    <img class="dash-img" src="${imgData}" />
  </div>

  <!-- ── Page 3: Insights ────────────────────────────────────────── -->
  <div class="insights-page">
    <div class="page-header">
      <div>
        <div class="page-title">AI Insights & Analysis</div>
        <div class="page-sub">Automatically generated insights from your dashboard data</div>
      </div>
      <div class="page-num">Talking BI · ${date}</div>
    </div>

    ${summary ? `
    <div class="summary-box">
      <h3>⚡ Executive Summary</h3>
      <p>${summary}</p>
    </div>
    ` : ""}

    <div class="section-title">📊 Chart-by-Chart Insights</div>
    ${insightRows}
  </div>

  <div class="pdf-footer">
    <span>Talking BI · AI-Powered Business Intelligence</span>
    <span>${dashboard_title} · ${date}</span>
  </div>

  <script>
    window.onload = function() { setTimeout(function(){ window.print(); }, 800); };
  <\/script>
</body>
</html>`);
      pw.document.close();
    } catch (e) {
      alert("PDF export failed: " + e.message);
    } finally { setExporting(false); setExportType(""); }
  };

  return (
    <div style={S.screen}>
      {/* ── Topbar ──────────────────────────────────────────────────────── */}
      <div style={S.topbar}>
        <div style={S.topLeft}>
          <div style={S.logoWrap}>
            <svg width="16" height="16" viewBox="0 0 28 28" fill="none">
              <circle cx="14" cy="14" r="12.5" stroke="#6366f1" strokeWidth="1.5"/>
              <path d="M8 19 L12 9 L16 15 L20 7" stroke="#6366f1" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="20" cy="7" r="2.2" fill="#a855f7"/>
            </svg>
          </div>
          <h1 style={S.title}>{dashboard_title}</h1>
          <div style={S.badge}>{total_kpis_generated} charts</div>
        </div>

        <div style={S.actions}>
          <div style={{ position:"relative" }}>
            <button
              style={{ ...S.exportBtn, ...(exporting ? S.off : {}) }}
              onClick={() => !exporting && setShowMenu(v => !v)}
              disabled={exporting}
            >
              {exporting ? (
                <><span style={S.spin}/>{exportType==="pdf"?"Saving PDF…":"Saving PNG…"}</>
              ) : (
                <>
                  <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                    <path d="M7 1v8M4.5 6.5l2.5 2.5 2.5-2.5M2 10.5v1.5a1 1 0 001 1h8a1 1 0 001-1v-1.5" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                  Export
                  <svg width="9" height="9" viewBox="0 0 9 9" fill="none">
                    <path d="M1.5 3l3 3 3-3" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
                  </svg>
                </>
              )}
            </button>

            {showMenu && (
              <div style={S.menu}>
                <button style={S.menuItem} onClick={exportPNG}>
                  <div style={S.mIcon}>
                    <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                      <rect x="1" y="1" width="12" height="12" rx="2" stroke="#6366f1" strokeWidth="1.2"/>
                      <circle cx="4.5" cy="5" r="1.2" fill="#6366f1"/>
                      <path d="M1 10l3.5-3.5 2.5 2.5 1.5-1.5 3.5 3.5" stroke="#6366f1" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round"/>
                    </svg>
                  </div>
                  <div><div style={S.mTitle}>Save as PNG</div><div style={S.mSub}>High-res image (2×)</div></div>
                </button>
                <div style={S.mSep}/>
                <button style={S.menuItem} onClick={exportPDF}>
                  <div style={{ ...S.mIcon, background:"rgba(245,158,11,0.08)", borderColor:"rgba(245,158,11,0.2)" }}>
                    <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                      <rect x="2" y="1" width="8" height="12" rx="1.5" stroke="#f59e0b" strokeWidth="1.2"/>
                      <path d="M4 4.5h4M4 7h4M4 9.5h2.5" stroke="#f59e0b" strokeWidth="1.2" strokeLinecap="round"/>
                      <path d="M8 1v3.5h4" stroke="#f59e0b" strokeWidth="1.2" strokeLinecap="round"/>
                    </svg>
                  </div>
                  <div><div style={{ ...S.mTitle, color:"#f59e0b" }}>Save as PDF</div><div style={S.mSub}>3-page professional report</div></div>
                </button>
              </div>
            )}
          </div>

          <button style={S.newBtn} onClick={onReset}>↺ New</button>
        </div>
      </div>

      {/* ── Body ────────────────────────────────────────────────────────── */}
      <div style={S.body}>
        <div style={S.main}>
          <div ref={exportRef} style={S.exportArea}>
            <div style={S.grid}>
              {charts.map((chart, i) => (
                <ChartCard key={chart.kpi} chart={chart} colorSchema={colorSchema} index={i} />
              ))}
            </div>
          </div>
        </div>

        <div style={S.sidebar}>
          <VoicePanel sessionId={sessionId} dashboardContext={voiceContext} />
          <InsightPanel insights={insights} summary={summary} />
        </div>
      </div>

      {showMenu && <div style={S.overlay} onClick={() => setShowMenu(false)} />}
    </div>
  );
